// src/screens/CreateGoalScreen.jsx
import React, { useState, useContext } from 'react';
import { ChevronLeft, Target, Calendar, DollarSign } from 'lucide-react';
import { CurrencyContext } from '../contexts/CurrencyContext';

/**
 * CreateGoalScreen Component
 * Interface for setting up a new financial goal.
 */
const CreateGoalScreen = ({ onBack, onSave }) => {
  const { currencySymbol } = useContext(CurrencyContext); // Dynamic currency
  const [goalName, setGoalName] = useState('');
  const [targetAmount, setTargetAmount] = useState('');
  const [targetDate, setTargetDate] = useState('');

  const handleSave = () => {
    if (!goalName || !targetAmount || !targetDate) return;
    onSave({ name: goalName, amount: parseFloat(targetAmount), date: targetDate });
  };

  return (
    <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">New Financial Goal</h1>
      </div>

      {/* Body */}
      <div className="p-6 flex-1 overflow-y-auto scrollbar-hide">
        <div className="flex justify-center mb-8">
          <div className="w-20 h-20 bg-emerald-50 rounded-[2rem] flex items-center justify-center text-[#00875A]">
            <Target size={40} strokeWidth={2.5} />
          </div>
        </div>

        <div className="space-y-6">
          {/* Goal Name */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Goal Name</label>
            <input 
              type="text" 
              placeholder="e.g. New MacBook Pro" 
              value={goalName}
              onChange={e => setGoalName(e.target.value)}
              className="w-full p-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] font-bold"
            />
          </div>

          {/* Target Amount */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Target Amount</label>
            <div className="relative">
              <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="number" 
                placeholder="0.00" 
                value={targetAmount}
                onChange={e => setTargetAmount(e.target.value)}
                className="w-full p-4 pl-12 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] font-black text-xl"
              />
              <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-400">{currencySymbol}</span>
            </div>
          </div>

          {/* Target Date */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Target Date</label>
            <div className="relative">
              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="date" 
                value={targetDate}
                onChange={e => setTargetDate(e.target.value)}
                className="w-full p-4 pl-12 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] font-bold"
              />
            </div>
          </div>

          {/* Tip */}
          <div className="p-5 bg-blue-50 rounded-[2rem] border border-blue-100">
            <p className="text-xs text-blue-700 font-bold leading-relaxed">
              💡 Tip: Setting a realistic date helps Nest suggest the perfect daily saving amount for you.
            </p>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="p-6 bg-white border-t border-gray-50">
        <button 
          onClick={handleSave}
          className="w-full py-4 rounded-2xl font-black text-white bg-[#00875A] shadow-lg shadow-emerald-100 active:scale-[0.98] transition-all"
        >
          Create Goal
        </button>
      </div>
    </div>
  );
};

export default CreateGoalScreen;
